function validateComposeFile(composeFile) {
  let services = composeFile.split('\n\n');
  let portMappings = {};

  for (let service of services) {
    let serviceName = service.split('\n')[0].trim();
    let ports = service.split('\n').filter(line => line.startsWith('ports:')).map(line => line.split(' ').pop().trim());

    for (let port of ports) {
      let [localPort, containerPort] = port.split(':').map(Number);

      if (portMappings[serviceName] && portMappings[serviceName].includes(containerPort)) {
        return [`${serviceName}:${containerPort}`];
      }

      if (!portMappings[serviceName]) {
        portMappings[serviceName] = [];
      }
      portMappings[serviceName].push(containerPort);
    }
  }

  let invalidPortMappings = [];

  for (let service in portMappings) {
    if (portMappings[service].length > 1) {
      for (let port of portMappings[service]) {
        if (port === 80) {
          invalidPortMappings.push(`${service}:${port}`);
        }
      }
    }
  }

  return invalidPortMappings;
}

